```python
import pytest
from functools import wraps

def memoize(fn):
    cache = {}
    def wrapper(*args):
        if args not in cache:
            cache[args] = fn(*args)
        return cache[args]
    return wrapper

def test_memoize_happy_path():
    @memoize
    def add(a, b):
        return a + b

    assert add(2, 3) == 5
    assert add(2, 3) == 5
    assert add(2, 3) == 5

def test_memoize_edge_case():
    @memoize
    def add(a, b):
        if a == 0:
            return 0
        return a + b

    assert add(0, 2) == 2
    assert add(0, 2) == 2
    assert add(0, 2) == 2

def test_memoize_error_case():
    @memoize
    def add(a, b):
        if a == 0:
            raise ValueError("Cannot divide by zero")
        return a + b

    with pytest.raises(ValueError):
        add(0, 2)
    with pytest.raises(ValueError):
        add(0, 0)
    with pytest.raises(ValueError):
        add(0, 2)
```
